CREATE TABLE `loupan_tupai_land` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `loupan_id` bigint DEFAULT NULL,
  `land_name` varchar(200) NOT NULL,
  `land_no` varchar(100) NOT NULL,
  `district` varchar(50) NOT NULL,
  `plate` varchar(50) DEFAULT '',
  `land_scope` text,
  `land_status` tinyint NOT NULL DEFAULT '0',
  `winner_company` varchar(100) NOT NULL,
  `land_use_type` varchar(100) NOT NULL,
  `land_year` int NOT NULL DEFAULT '70',
  `land_area` decimal(10,2) NOT NULL,
  `build_area_limit` decimal(12,2) DEFAULT NULL,
  `plot_ratio` decimal(3,2) DEFAULT NULL COMMENT '容积率上限',
  `start_price` bigint NOT NULL DEFAULT '0',
  `deal_price` bigint NOT NULL DEFAULT '0',
  `floor_unit_price` int DEFAULT NULL COMMENT '楼面单价 元/㎡',
  `premium_rate` decimal(5,2) DEFAULT NULL COMMENT '溢价率 %',
  `deal_date` date NOT NULL,
  `sort` int NOT NULL DEFAULT '0',
  `deleted` tinyint NOT NULL DEFAULT '0',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `longitude` decimal(12,6) DEFAULT NULL COMMENT '经度',
  `latitude` decimal(12,6) DEFAULT NULL COMMENT '纬度',
  `resource_id` varchar(100) DEFAULT '2074308954934083584' COMMENT '资源ID',
  `location_image` varchar(500) DEFAULT NULL COMMENT '位置示意图URL',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_land_no` (`land_no`),
  KEY `idx_loupan_id` (`loupan_id`),
  KEY `idx_district_plate` (`district`,`plate`),
  KEY `idx_deal_date` (`deal_date`)
) ENGINE=InnoDB AUTO_INCREMENT=1103 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
